#!/bin/bash
#
# Sol-Fortress v3.0 — One-Shot Deployment Script
# Run this ON THE SERVER via SSH
# It will: backup old files, write new ones, verify syntax, restart service
#
set -e

echo "============================================"
echo "  Sol-Fortress v3.0 — DEPLOY"
echo "============================================"
echo ""

DEST="/home/solbot/fortress"
BACKUP="$DEST/backup_$(date +%Y%m%d_%H%M%S)"

# Step 1: Create backup
echo "[1/5] Backing up current files..."
mkdir -p "$BACKUP"
cp -f "$DEST/fort_v2.py" "$BACKUP/fort_v2.py" 2>/dev/null && echo "  ✓ fort_v2.py backed up" || echo "  (no fort_v2.py to back up)"
cp -f "$DEST/learning_engine.py" "$BACKUP/learning_engine.py" 2>/dev/null && echo "  ✓ learning_engine.py backed up" || echo "  (no learning_engine.py to back up)"
cp -f "$DEST/self_regulation.py" "$BACKUP/self_regulation.py" 2>/dev/null && echo "  ✓ self_regulation.py backed up" || echo "  (no self_regulation.py to back up)"
echo "  Backup folder: $BACKUP"
echo ""

# Step 2: Write new files from embedded base64
echo "[2/5] Writing v3.0 files..."

echo '' | base64 -d > "$DEST/fort_v2.py"
echo "  ✓ fort_v2.py written ($(wc -l < $DEST/fort_v2.py) lines)"
echo '' | base64 -d > "$DEST/learning_engine.py"
echo "  ✓ learning_engine.py written ($(wc -l < $DEST/learning_engine.py) lines)"
echo '' | base64 -d > "$DEST/self_regulation.py"
echo "  ✓ self_regulation.py written ($(wc -l < $DEST/self_regulation.py) lines)"
echo ""

# Step 3: Set ownership
echo "[3/5] Setting ownership..."
chown solbot:solbot "$DEST/fort_v2.py" "$DEST/learning_engine.py" "$DEST/self_regulation.py"
echo "  ✓ All files owned by solbot"
echo ""

# Step 4: Syntax check
echo "[4/5] Syntax verification..."
FAIL=0

/home/solbot/fortress/venv/bin/python3 -c "
import py_compile, sys
for f in ['$DEST/fort_v2.py', '$DEST/learning_engine.py', '$DEST/self_regulation.py']:
    try:
        py_compile.compile(f, doraise=True)
        print(f'  ✓ {f.split(\"/\")[-1]} — syntax OK')
    except py_compile.PyCompileError as e:
        print(f'  ✗ {f.split(\"/\")[-1]} — SYNTAX ERROR: {e}')
        sys.exit(1)
" || FAIL=1

if [ "$FAIL" = "1" ]; then
    echo ""
    echo "╔══════════════════════════════════════════╗"
    echo "║  SYNTAX ERROR — ROLLING BACK             ║"
    echo "╚══════════════════════════════════════════╝"
    cp -f "$BACKUP/fort_v2.py" "$DEST/fort_v2.py" 2>/dev/null
    cp -f "$BACKUP/learning_engine.py" "$DEST/learning_engine.py" 2>/dev/null
    cp -f "$BACKUP/self_regulation.py" "$DEST/self_regulation.py" 2>/dev/null
    echo "Old files restored from $BACKUP"
    exit 1
fi
echo ""

# Step 5: Restart service
echo "[5/5] Restarting bot service..."
systemctl restart sol-fortress-v2
sleep 3

# Verify
STATUS=$(systemctl is-active sol-fortress-v2)
echo ""
echo "============================================"
if [ "$STATUS" = "active" ]; then
    echo "  ✅ DEPLOYMENT SUCCESS"
    echo "  Service: $STATUS"
    echo ""
    echo "  Checking startup log..."
    journalctl -u sol-fortress-v2 --no-pager -n 15 --since "10 seconds ago"
    echo ""
    echo "  VERIFY THESE THINGS IN THE LOG:"
    echo "    1. Version shows 'v3.0' (not v2.0)"
    echo "    2. No GHOST-TRAP messages"
    echo "    3. No 'LEARNING_ENGINE_READY' at startup"
    echo "    4. Mode shows PAPER"
else
    echo "  ❌ SERVICE FAILED TO START"
    echo "  Status: $STATUS"
    echo ""
    echo "  Showing error log:"
    journalctl -u sol-fortress-v2 --no-pager -n 30 --since "30 seconds ago"
    echo ""
    echo "  To rollback: cp $BACKUP/* $DEST/ && systemctl restart sol-fortress-v2"
fi
echo "============================================"
